// Analyze trends from historical data
const items = $input.all();
const weeklyTraffic = items.filter(i => i.json.week_start).map(i => i.json);
const rankingHistory = items.filter(i => i.json.keyword).map(i => i.json);

const trends = [];

// Traffic trend analysis
if (weeklyTraffic.length >= 4) {
  const recent = weeklyTraffic.slice(0, 4);
  const older = weeklyTraffic.slice(4, 8);

  const recentAvg = recent.reduce((sum, w) => sum + (w.total_sessions || 0), 0) / recent.length;
  const olderAvg = older.length > 0 ? older.reduce((sum, w) => sum + (w.total_sessions || 0), 0) / older.length : recentAvg;

  const change = olderAvg > 0 ? ((recentAvg - olderAvg) / olderAvg) * 100 : 0;

  if (Math.abs(change) >= 10) {
    trends.push({
      trend_type: 'traffic_trend',
      name: change > 0 ? 'Traffic Growth Trend' : 'Traffic Decline Trend',
      description: `Traffic has ${change > 0 ? 'increased' : 'decreased'} by ${Math.abs(change).toFixed(1)}% over the last 4 weeks`,
      direction: change > 0 ? 'up' : 'down',
      magnitude: Math.abs(change),
      data_points: JSON.stringify(recent.map(w => ({ date: w.week_start, value: w.total_sessions }))),
      is_active: true
    });
  }
}

// Keyword ranking trends
const keywordGroups = {};
rankingHistory.forEach(r => {
  if (!keywordGroups[r.keyword]) keywordGroups[r.keyword] = [];
  keywordGroups[r.keyword].push(r);
});

Object.entries(keywordGroups).forEach(([keyword, history]) => {
  if (history.length < 7) return;

  const recent = history.slice(-7);
  const older = history.slice(-14, -7);

  if (older.length === 0) return;

  const recentAvg = recent.reduce((sum, r) => sum + (r.position || 100), 0) / recent.length;
  const olderAvg = older.reduce((sum, r) => sum + (r.position || 100), 0) / older.length;

  const improvement = olderAvg - recentAvg;  // Positive = improved

  if (Math.abs(improvement) >= 5) {
    trends.push({
      trend_type: 'ranking_trend',
      name: `${keyword} Ranking ${improvement > 0 ? 'Improvement' : 'Decline'}`,
      description: `"${keyword}" has ${improvement > 0 ? 'improved' : 'declined'} by ${Math.abs(improvement).toFixed(1)} positions`,
      direction: improvement > 0 ? 'up' : 'down',
      magnitude: Math.abs(improvement),
      data_points: JSON.stringify(recent.map(r => ({ date: r.collected_date, value: r.position }))),
      is_active: true
    });
  }
});

return trends.length > 0 ? trends.map(t => ({ json: t })) : [{ json: { no_trends: true } }];
